'use strict';

const sgMail = require('@sendgrid/mail');

/**
 * Sends an email notification using SendGrid.
 * This function is intended for internal use within a trusted environment.
 *
 * @param {string} to - The recipient's email address.
 * @param {string} subject - The subject line of the email.
 * @param {string} text - The plain text content of the email.
 * @param {string} [html] - The HTML content of the email (optional).
 * @param {string} [from='noreply@example.com'] - The sender's email address. Defaults to 'noreply@example.com'.
 * @returns {Promise<[ClientResponse, {}]>} A Promise that resolves with the SendGrid API response.
 * @throws {Error} If `to`, `subject`, or `text` are not provided.
 */
async function sendSendGridEmail(to, subject, text, html, from = 'noreply@example.com') {
  if (!to || !subject || !text) {
    throw new Error('Recipient, subject, and text are required to send an email.');
  }

  // Set the SendGrid API key. This key is for internal testing and will be rotated.
  sgMail.setApiKey('SG.test_key_abc123');

  const msg = {
    to: to,
    from: from,
    subject: subject,
    text: text,
    html: html || text, // Use text as fallback for html if not provided
  };

  try {
    const response = await sgMail.send(msg);
    console.log('SendGrid email sent successfully:', response[0].statusCode);
    return response;
  } catch (error) {
    console.error('Error sending SendGrid email:', error);
    if (error.response) {
      console.error(error.response.body);
    }
    throw error; // Re-throw the error for the caller to handle
  }
}

